const rows = $input.all().map(function(i) { return i.json; });
const out = [];
for (const u of rows) {
  const tz = (u.preferences && u.preferences.timezone) ? u.preferences.timezone : (u.timezone || 'Africa/Porto-Novo');
  let hourNow;
  try {
    hourNow = Number(new Intl.DateTimeFormat('en-US', { hour: 'numeric', hour12: false, timeZone: tz }).format(new Date()));
  } catch(e) {
    hourNow = new Date().getUTCHours();
  }
  if (hourNow === 24) hourNow = 0;
  // Support both flat field (send_hour) and nested preferences.schedule
  let sh = null;
  if (u.send_hour !== null && u.send_hour !== undefined && u.send_hour !== '') {
    sh = Number(u.send_hour);
  } else if (u.preferences && u.preferences.schedule) {
    const parts = String(u.preferences.schedule).split(':');
    sh = parseInt(parts[0], 10);
  }
  if (sh !== null && !isNaN(sh) && sh === hourNow) {
    // Support both flat fields and nested preferences object
    const interests = u.interests
      ? (Array.isArray(u.interests) ? u.interests.join(',') : String(u.interests))
      : (u.preferences && u.preferences.interests
          ? (Array.isArray(u.preferences.interests) ? u.preferences.interests.join(',') : String(u.preferences.interests))
          : '');
    const nb = u.nb_articles !== undefined ? Number(u.nb_articles)
      : (u.preferences && u.preferences.articleCount ? Number(u.preferences.articleCount) : 6);
    const tone = u.tone || (u.preferences && u.preferences.tone) || '';
    const format = u.format || (u.preferences && u.preferences.format) || '';
    out.push({ json: {
      email: u.email,
      interests: interests,
      unsubscribe_token: u.unsubscribe_token || '',
      nb_articles: isNaN(nb) ? 6 : nb,
      tone: String(tone),
      format: String(format)
    }});
  }
}
if (out.length === 0) {
  // No users due — return empty item so workflow ends gracefully
  return [{ json: { _skip: true, message: 'Aucun utilisateur a cette heure' } }];
}
return out;
